def semantic_similarity(a: str, b: str) -> float:
    va = embedder.embed_query(a)
    vb = embedder.embed_query(b)
    # dot product of normalised vectors = cosine similarity
    import numpy as np
    va, vb = np.array(va), np.array(vb)
    return float(np.dot(va / np.linalg.norm(va), vb / np.linalg.norm(vb)))

def iterative_rag_with_convergence(
    question: str,
    max_hops: int = 5,
    convergence_threshold: float = 0.97,
) -> str:
    context = []
    prev_answer = ""

    for hop in range(max_hops):
        query = refine_query(question, prev_answer, context)  # see below
        context.append(retrieve(query))
        answer = generate_answer(question, context)

        if prev_answer and semantic_similarity(answer, prev_answer) > convergence_threshold:
            return answer  # converged

        prev_answer = answer

    return prev_answer  # return best answer at max_hops

def refine_query(question: str, prev_answer: str, context: list[str]) -> str:
    if not prev_answer:
        return question
    prompt = (
        f"Original question: {question}\n\n"
        f"Current partial answer: {prev_answer}\n\n"
        "What specific information is still missing? "
        "Write a targeted search query to find it. "
        "Return only the query, nothing else."
    )
    return llm.invoke(prompt).content.strip()

def iterative_rag_no_repeats(
    question: str,
    max_hops: int = 5,
) -> str:
    retrieved_ids: set[str] = set()
    context_chunks: list[str] = []
    answer = ""

    for hop in range(max_hops):
        # Generate search query based on gaps in current knowledge
        search_query = refine_query(question, answer, context_chunks)
        docs_and_scores = store.similarity_search_with_relevance_scores(search_query, k=5)

        # Filter out already-seen chunks
        new_chunks = []
        for doc, score in docs_and_scores:
            doc_id = doc.metadata.get("chunk_id") or hash(doc.page_content)
            if str(doc_id) not in retrieved_ids and score > 0.3:
                retrieved_ids.add(str(doc_id))
                new_chunks.append(doc.page_content)

        if not new_chunks:
            break  # no new information available

        context_chunks.extend(new_chunks)

        # Summarise if context grows too large
        if len(" ".join(context_chunks)) > 4000:
            context_chunks = [summarise_context(question, context_chunks)]

        answer = generate_answer(question, context_chunks)

    return answer

def generate_answer(question: str, context_chunks: list[str]) -> str:
    context = "\n\n".join(context_chunks)
    return llm.invoke(
        f"Context:\n{context}\n\nQuestion: {question}\n\nAnswer:"
    ).content.strip()

def hop_coverage(
    retrieved_per_hop: list[list[str]],  # list of doc IDs per hop
    ground_truth_docs: list[str],         # required doc IDs
) -> float:
    all_retrieved = {doc_id for hop in retrieved_per_hop for doc_id in hop}
    found = all_retrieved.intersection(ground_truth_docs)
    return len(found) / len(ground_truth_docs) if ground_truth_docs else 1.0

from statistics import mean

def retrieval_efficiency(hop_counts: list[int], correct_flags: list[bool]) -> float:
    """Mean hops for questions answered correctly. Lower is better."""
    correct_hops = [h for h, ok in zip(hop_counts, correct_flags) if ok]
    return mean(correct_hops) if correct_hops else float("inf")
